Bash(bun -e "
const fs = require\('fs'\);
const path = 'C:/Users/joaoc/Documents/Code/JS-TS/Bun/cowboyGame/src/game.ts';
let c = fs.readFileSync\(path, 'utf-8'\);

// 5. Update click handler for book - add tab support
const oldClickHandler = \\`    if \(this.bookOpen\) {
      const BW = Math.min\(W - 32, 500\),
        BH = Math.min\(H - 32, 620\);
      const BX = \(W - BW\) / 2,
        BY = \(H - BH\) / 2;
      const closeCX = BX + BW - 30,
        closeCY = BY + 28;
      if \(Math.hypot\(x - closeCX, y - closeCY\) < 28\) {
        this.bookOpen = false;
        return;
      }
      // Prev / Next nav buttons \(bottom centre of parchment\)
      const parchX = BX + 26,
        parchY = BY + 37;
      const parchH = BH - 74;
      const navY = parchY + parchH - 28;
      const prevCX = BX + BW / 2 - 70;
      const nextCX = BX + BW / 2 + 70;
      if \(Math.hypot\(x - prevCX, y - navY\) < 28\) {
        this.bookFlipPage\(-1\);
        return;
      }
      if \(Math.hypot\(x - nextCX, y - navY\) < 28\) {
        this.bookFlipPage\(1\);
        return;
      }
      // Click outside panel closes book
      if \(x < BX || x > BX + BW || y < BY || y > BY + BH\) {
        this.bookOpen = false;
        return;
      }
      return; // swallow input while book is open
    }\\`;

const newClickHandler = \\`    if \(this.bookOpen\) {
      const BW = Math.min\(W - 32, 500\),
        BH = Math.min\(H - 32, 620\);
      const BX = \(W - BW\) / 2,
        BY = \(H - BH\) / 2;
      const closeCX = BX + BW - 30,
        closeCY = BY + 28;
      if \(Math.hypot\(x - closeCX, y - closeCY\) < 28\) {
        this.bookOpen = false;
        return;
      }
      // Tab clicks
      const parchX = BX + 26,
        parchY = BY + 37;
      const parchW = BW - 50;
      const tabs: Array<\\"vacas\\" | \\"itens\\" | \\"personagens\\"> = [
        \\"vacas\\",
        \\"itens\\",
        \\"personagens\\",
      ];
      const tabW = \(parchW - 20\) / 3;
      const tabY = parchY + 38;
      const tabH = 24;
      for \(let i = 0; i < tabs.length; i++\) {
        const tx = parchX + 10 + i * tabW;
        if \(x >= tx && x <= tx + tabW && y >= tabY && y <= tabY + tabH\) {
          this.bookTab = tabs[i]!;
          this.bookPage = 0;
          this.bookPageTarget = 0;
          this.bookPageAnimT = 1;
          return;
        }
      }
      // Prev / Next nav buttons \(bottom centre of parchment\)
      const parchH = BH - 74;
      const navY = parchY + parchH - 28;
      const prevCX = BX + BW / 2 - 70;
      const nextCX = BX + BW / 2 + 70;
      if \(this.bookTab === \\"vacas\\" || this.bookTab === \\"personagens\\"\) {
        if \(Math.hypot\(x - prevCX, y - navY\) < 28\) {
          this.bookFlipPage\(-1\);
          return;
        }
        if \(Math.hypot\(x - nextCX, y - navY\) < 28\) {
          this.bookFlipPage\(1\);
          return;
        }
      }
      // Click outside panel closes book
      if \(x < BX || x > BX + BW || y < BY || y > BY + BH\) {
        this.bookOpen = false;
        return;
      }
      return; // swallow input while book is open
    }\\`;

if \(c.includes\(oldClickHandler\)\) {
  c = c.replace\(oldClickHandler, newClickHandler\);
  fs.writeFileSync\(path, c, 'utf-8'\);
  console.log\('Click handler updated'\);
} else {
  console.log\('ERROR: click handler not found'\);
}
")

